        InvestorData storage data = investorData[msg.sender];
        uint256 availableAmount = data.allocation - data.withdrawn;
        require(block.timestamp >= data.releaseTime, "Release time not reached");
        require(availableAmount > 0, "No funds available for withdrawal");

